SELECT * FROM exit_record WHERE 1=1

    AND actual_exit >= #{begin}


    AND actual_exit <= #{end}

ORDER BY actual_exit DESC

SELECT * FROM exit_record WHERE 1=1

    AND actual_exit >= #{begin}


    AND actual_exit <= #{end}


    AND plate_number LIKE CONCAT('%', #{plate}, '%')


    AND spot_no LIKE CONCAT('%', #{spotNo}, '%')

ORDER BY actual_exit DESC

SELECT spot_no AS name, SUM(total_fee) AS number FROM exit_record WHERE 1=1
AND actual_exit >= #{begin}
AND actual_exit <= #{end}
GROUP BY spot_no ORDER BY SUM(total_fee) DESC LIMIT 10

SELECT CONCAT(driver_name, '(', plate_number, ')') AS name, COUNT(*) AS number FROM exit_record WHERE 1=1
AND actual_exit >= #{begin}
AND actual_exit <= #{end}
GROUP BY driver_no, driver_name, plate_number ORDER BY COUNT(*) DESC LIMIT 10

SELECT st.name AS name, COUNT(*) AS number FROM exit_record er INNER JOIN parking_spot ps ON er.spot_no = ps.spot_no INNER JOIN spot_type st ON ps.type_id = st.id WHERE 1=1
AND er.actual_exit >= #{begin}
AND er.actual_exit <= #{end}
GROUP BY st.id, st.name ORDER BY COUNT(*) DESC LIMIT 10
